DROP TABLE IF EXISTS `Access`;
CREATE TABLE `Access` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `debug` tinyint,
  `schema` varchar(100),
  `name` varchar(50),
  `alias` varchar(20),
  `get` varchar(100),
  `head` varchar(100),
  `gets` varchar(100),
  `heads` varchar(100),
  `post` varchar(100),
  `put` varchar(100),
  `delete` varchar(100),
  `date` datetime,
  `detail` varchar(1000)
);


